import { FileText } from "lucide-react";
import type { Cotacao } from "@/lib/cotacoes-store";
import type { Voo } from "@/components/cotacoes/FlightCard";
import { dateOnlyToBR } from "@/lib/dates";

const LOGO_WHITE = "data:image/png;base64,";
const LOGO_BLUE  = "data:image/png;base64,";

// ─── helpers ────────────────────────────────────────────────────────────────

function diaSemanaFull(dateStr?: string): string {
  if (!dateStr) return "";
  // dateStr pode ser "DD-MM-AAAA" ou "AAAA-MM-DD"
  let d: number, m: number, a: number;
  const parts = dateStr.split(/[-/]/);
  if (parts[0].length === 4) {
    [a, m, d] = parts.map(Number);
  } else {
    [d, m, a] = parts.map(Number);
  }
  const dt = new Date(a, m - 1, d);
  const semana = dt.toLocaleDateString("pt-BR", { weekday: "long" });
  const data   = dt.toLocaleDateString("pt-BR", { day: "2-digit", month: "2-digit", year: "numeric" });
  return `${semana.charAt(0).toUpperCase() + semana.slice(1)}, ${data}`;
}

function fmtHora(h?: string) {
  return h ? h.substring(0, 5) : "—";
}

function fmtData(dateStr?: string): string {
  if (!dateStr) return "";
  const parts = dateStr.split(/[-/]/);
  let d: number, m: number, a: number;
  if (parts[0].length === 4) {
    [a, m, d] = parts.map(Number);
  } else {
    [d, m, a] = parts.map(Number);
  }
  return `${String(d).padStart(2,"0")}/${String(m).padStart(2,"0")}/${a}`;
}

interface Trecho {
  origem: string;
  destino: string;
  numeroVoo: string;
  horaSaida: string;
  horaChegada: string;
  data: string;
  dataChegada: string;
}

function getTrechos(voo?: Voo): Trecho[] {
  if (!voo) return [];
  if (voo.tipo === "com_escala" && voo.escalas?.length) {
    return voo.escalas.map((e) => ({
      origem:      e.origem   ?? "—",
      destino:     e.destino  ?? "—",
      numeroVoo:   e.numeroVoo ? `Voo ${e.numeroVoo}` : "—",
      horaSaida:   fmtHora(e.saida),
      horaChegada: fmtHora(e.chegada),
      data:        fmtData(e.dataInicio),
      dataChegada: fmtData(e.dataFim),
    }));
  }
  return [{
    origem:      voo.origem    ?? "—",
    destino:     voo.destino   ?? "—",
    numeroVoo:   voo.numeroVoo ? `Voo ${voo.numeroVoo}` : "—",
    horaSaida:   fmtHora(voo.horaSaida),
    horaChegada: fmtHora(voo.horaChegada),
    data:        fmtData(voo.data),
    dataChegada: fmtData(voo.dataChegada ?? voo.data),
  }];
}

function getBagagens(voo?: Voo) {
  if (!voo?.bagagens) return { mao: 0, desp: 0 };
  const b = voo.bagagens;
  return {
    mao:  (b.pessoal ?? 0) + (b.maoCabine ?? 0),
    desp: (b.despachada23 ?? 0) + (b.despachada32 ?? 0),
  };
}

// ─── Render de itinerário ────────────────────────────────────────────────────

function renderItinerario(voos: Voo[], label: string): string {
  if (!voos.length) return "";
  return voos.map((voo) => {
    const ts = getTrechos(voo);
    const dataHeader = diaSemanaFull(voo.data);
    const qtd = ts.length;
    return `
      <div style="margin-bottom:20px;">
        <div style="background:#0f1f3d;color:#fff;padding:12px 20px;display:flex;align-items:center;justify-content:space-between;border-radius:8px 8px 0 0;">
          <div style="display:flex;align-items:center;gap:10px;">
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M22 16.92v3a2 2 0 0 1-2.18 2 19.79 19.79 0 0 1-8.63-3.07A19.5 19.5 0 0 1 4.64 12a19.79 19.79 0 0 1-3.07-8.67A2 2 0 0 1 3.55 1h3a2 2 0 0 1 2 1.72c.127.96.361 1.903.7 2.81a2 2 0 0 1-.45 2.11L8.09 8.91a16 16 0 0 0 6 6l1.27-1.27a2 2 0 0 1 2.11-.45c.907.339 1.85.573 2.81.7A2 2 0 0 1 22 16.92z"/></svg>
            <strong style="font-size:13px;letter-spacing:0.3px;">Itinerário de ${label}</strong>
          </div>
          <span style="font-size:12px;font-weight:500;">${dataHeader}</span>
          <span style="font-size:12px;">${qtd} ${qtd === 1 ? "Trecho" : "Trechos"}</span>
        </div>
        ${ts.map((t) => `
          <div style="border:1px solid #e2e8f0;border-top:none;padding:18px 20px;display:grid;grid-template-columns:1fr auto 1fr;align-items:center;gap:16px;background:#fff;">
            <div>
              <div style="font-size:26px;font-weight:800;color:#0f1f3d;line-height:1;">${t.horaSaida}</div>
              <div style="font-size:12px;color:#64748b;margin-top:3px;">${t.data}</div>
              <div style="font-size:12px;color:#334155;margin-top:6px;font-weight:500;">Aeroporto</div>
              <div style="font-size:12px;color:#3b82f6;margin-top:1px;">${t.origem}</div>
            </div>
            <div style="text-align:center;padding:0 8px;">
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#94a3b8" stroke-width="1.5"><path d="M22 2L11 13M22 2l-7 20-4-9-9-4 20-7z"/></svg>
              <div style="font-size:11px;color:#64748b;margin-top:4px;">${t.numeroVoo}</div>
            </div>
            <div style="text-align:right;">
              <div style="font-size:26px;font-weight:800;color:#0f1f3d;line-height:1;">${t.horaChegada}</div>
              <div style="font-size:12px;color:#64748b;margin-top:3px;">${t.dataChegada || t.data}</div>
              <div style="font-size:12px;color:#334155;margin-top:6px;font-weight:500;">Aeroporto</div>
              <div style="font-size:12px;color:#3b82f6;margin-top:1px;">${t.destino}</div>
            </div>
          </div>
        `).join("")}
      </div>
    `;
  }).join("");
}

// ─── Render de passageiros ───────────────────────────────────────────────────

function renderPassageiros(passageiros: string[], voosIda: Voo[], voosVolta: Voo[]): string {
  return passageiros.map((nome) => {
    const bagIda   = getBagagens(voosIda[0]);
    const bagVolta = getBagagens(voosVolta[0]);
    const temIda   = voosIda.length > 0;
    const temVolta = voosVolta.length > 0;

    function colPassageiro(label: string, bag: { mao: number; desp: number }) {
      return `
        <div style="flex:1;padding:0 16px;">
          <div style="display:flex;align-items:center;gap:6px;margin-bottom:10px;">
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#3b82f6" stroke-width="2"><path d="M22 2L11 13M22 2l-7 20-4-9-9-4 20-7z"/></svg>
            <span style="font-size:12px;font-weight:600;color:#64748b;">${label}</span>
          </div>
          <div style="display:flex;justify-content:space-between;align-items:flex-start;border-top:1px dashed #e2e8f0;padding-top:10px;">
            <div>
              <div style="font-size:11px;color:#94a3b8;margin-bottom:4px;">Assentos</div>
              <div style="font-size:12px;color:#94a3b8;">Nenhum assento definido.</div>
            </div>
            <div>
              <div style="font-size:11px;color:#94a3b8;margin-bottom:6px;text-align:right;">Bagagens</div>
              <div style="display:flex;gap:16px;align-items:flex-end;">
                <div style="text-align:center;">
                  <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#3b82f6" stroke-width="1.5"><rect x="2" y="7" width="20" height="14" rx="2"/><path d="M16 7V5a2 2 0 0 0-2-2h-4a2 2 0 0 0-2 2v2"/></svg>
                  <div style="font-size:14px;font-weight:700;color:#334155;">${bag.mao}</div>
                  <div style="font-size:10px;color:#94a3b8;">10kg</div>
                </div>
                <div style="text-align:center;">
                  <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#3b82f6" stroke-width="1.5"><rect x="2" y="7" width="20" height="14" rx="2"/><path d="M16 7V5a2 2 0 0 0-2-2h-4a2 2 0 0 0-2 2v2"/></svg>
                  <div style="font-size:14px;font-weight:700;color:#334155;">${bag.desp}</div>
                  <div style="font-size:10px;color:#94a3b8;">23kg</div>
                </div>
              </div>
            </div>
          </div>
        </div>
      `;
    }

    return `
      <div style="border:1px solid #e2e8f0;border-radius:8px;margin-bottom:12px;overflow:hidden;background:#fff;">
        <div style="background:#f8fafc;padding:12px 20px;border-bottom:1px solid #e2e8f0;">
          <span style="font-size:13px;font-weight:700;color:#0f1f3d;text-transform:uppercase;letter-spacing:0.5px;">${nome}</span>
        </div>
        <div style="display:flex;padding:16px 4px;">
          ${temIda   ? colPassageiro("Ida",   bagIda)   : ""}
          ${temIda && temVolta ? '<div style="width:1px;background:#e2e8f0;margin:0 4px;"></div>' : ""}
          ${temVolta ? colPassageiro("Volta", bagVolta) : ""}
        </div>
      </div>
    `;
  }).join("");
}

